import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: empty and simple base premiums ---
  it.todo("empty item list → premium 5 G (only the processing fee)");
  it.todo("single sword (steel, enchantment 3, not cursed), newcomer, first contract → 100 base + 10 first + 5 fee = 115 G");
  it.todo("single amulet (silver, enchantment 2, not cursed), newcomer, first contract → 60 base + 6 first + 5 fee = 71 G");
  it.todo("single staff base 800/80 G premium");
  it.todo("single potion base 400/40 G premium");

  // --- Components & blocks ---
  it.todo("2 runes → 50 G base premium (no block) - quote total: 50 + 5 first + 5 fee = 60 G");
  it.todo("3 runes → 60 G base (block applies)");
  it.todo("4 runes → 100 G base (no block, block requires exactly 3)");
  it.todo("7 runes → 175 G base");
  it.todo("2 runes + 1 moonstone → 75 G base (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base (two separate blocks)");

  // --- Premium modifiers (per-item and policy-wide) ---
  it.todo("cursed sword (steel, enchantment 3), newcomer first contract → 165 G (integration example)");
  it.todo("cursed sword + plain amulet on same policy applies cursed surcharge only to the sword");
  it.todo("loyalty discount applies at exactly 2 years");
  it.todo("high-enchantment surcharge applies at exactly enchantment 5");
  it.todo("no high-enchantment surcharge at enchantment 4");
  it.todo("long-standing customer's second contract cursed enchantment-7 sword → 160 G (integration example)");

  // --- Rounding ---
  it.todo("premium rounding is up (MHPCO's favor): 197.5 → 198");

  // --- Quote validation ---
  it.todo("quote with unknown item type → CLI non-zero exit");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword enchantment 3 damage 500 → payout 400 (full minus deductible)");
  it.todo("damage to a rune insurance value 250, damage 200 → payout 100 (no special clause)");

  // --- Claim: high-enchantment clause ---
  it.todo("steel sword enchantment 9 damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon sword enchantment 9 damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon sword enchantment 5 damage 800 → payout 700 (dragon full, then deductible)");
  it.todo("dragon-material sword enchantment 8 damage 1000 → payout 400 (high-enchant applies, then deductible)");

  // --- Claim: multiple damages ---
  it.todo("dragon attack damages sword 500 and amulet 300 → payout 600 (deductible per damage)");

  // --- Claim: cap ---
  it.todo("sword cap 2000, two claims of 1500 each → first 1400 (cap remaining 600), second 600 (cap remaining 0)");

  // --- Claim: payout rounding ---
  it.todo("payout 350.5 → 350 (rounded down, MHPCO's favor)");

  // --- Claim: validation ---
  it.todo("claim with negative damage amount → CLI non-zero exit");
  it.todo("claim references item not on policy → CLI non-zero exit");
  it.todo("damages contain more entries of a type than the policy covers → CLI non-zero exit");

  // --- Multi-step scenario ---
  it.todo("scenario with quote then claim produces results array in step order");
});

