type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };
type Result = QuoteResult;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results = scenario.steps.map((step) => {
    const itemBase = step.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
    if (step.items.length === 0) return { premium: 5 };
    const firstInsurance = itemBase * 0.1;
    return { premium: Math.ceil(itemBase + firstInsurance + 5) };
  });
  return { results };
};

