type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };
type Result = QuoteResult;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60;

const isMainItem = (type: string): boolean => type in BASE_PREMIUMS;

const computeItemBasePremiums = (items: Item[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (isMainItem(item.type)) {
      total += BASE_PREMIUMS[item.type];
    } else {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }
  for (const type in componentCounts) {
    const count = componentCounts[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    total += blocks * COMPONENT_BLOCK_BASE + remainder * COMPONENT_BASE;
  }
  return total;
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results = scenario.steps.map((step) => {
    const itemBase = computeItemBasePremiums(step.items);
    const firstInsurance = itemBase * 0.1;
    return { premium: Math.ceil(itemBase + firstInsurance + 5) };
  });
  return { results };
};

